+/**
+ * Replaces recur schema placeholders.
+ *
+ * @param value The value to be processed.
+ * @param schema The recursive schema.
+ * @param cache The cache of processed values.
+ *
+ * @returns The processed value.
+ *
+ * @internal
+ */
+export function _replaceRecur(
+  value: unknown,
+  schema: unknown,
+  cache = new WeakMap<object, unknown>()
+): unknown {
+  if (value === Recur) {
+    return schema;
+  }
+
+  if (Array.isArray(value)) {
+    const clone: unknown[] = [];
+    cache.set(value, clone);
+    for (const item of value) {
+      clone.push(_replaceRecur(item, schema, cache));
+    }
+    return clone;
+  }
+
+  if (
+    value &&
+    typeof value === 'object' &&
+    Object.getPrototypeOf(value) === Object.prototype
+  ) {
+    const cached = cache.get(value);
+    if (cached) {
+      return cached;
+    }
+
+    const clone = Object.create(Object.getPrototypeOf(value));
+    cache.set(value, clone);
+    for (const key of Reflect.ownKeys(value)) {
+      const descriptor = Object.getOwnPropertyDescriptor(value, key)!;
+      if ('value' in descriptor) {
+        descriptor.value = _replaceRecur(descriptor.value, schema, cache);
+      }
+      Object.defineProperty(clone, key, descriptor);
+    }
+    return clone;
+  }
+
+  return value;
